class Solution:
    def isSafe(self, board, row, col, n):
        for i in range(n):
            if board[i][col] == 'Q': return False
            if i != row and (abs(i - row) == abs(col - col) or abs(i - row) == abs(col - n)): return False
        return True
    def totalNQueens(self, n):
        board = [['.' for _ in range(n)] for _ in range(n)]
        count = 0
        def backtrack(board, row, n, count):
            nonlocal count
            if row == n: count += 1
            for col in range(n):
                if self.isSafe(board, row, col, n):
                    board[row][col] = 'Q'
                    backtrack(board, row + 1, n, count)
                    board[row][col] = '.'
        backtrack(board, 0, n, count)
        return count
